1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import {
3	  ActivityIndicator,
4	  Linking,
5	  Pressable,
6	  SafeAreaView,
7	  ScrollView,
8	  StyleSheet,
9	  Text,
10	  View,
11	} from 'react-native';
12	import { router, useLocalSearchParams } from 'expo-router';
13	import { Check, ChevronLeft, ExternalLink, X } from 'lucide-react-native';
14	import { ButtonPrimary } from '@/components/primitives/Button';
15	import { StatusPill } from '@/components/primitives/StatusPill';
16	import { useToast } from '@/components/primitives/Toast';
17	import { colors, radii, shadows, spacing } from '@/design/tokens';
18	import { textStyles } from '@/design/typography';
19	import { supabase } from '@/lib/supabase';
20	import type { Database } from '@/types/supabase';
21	import { ApplySheet, type ApplyFailure } from '@/screens/listing-detail/ApplySheet';
22	
23	// US-040 — Campaign detail screen. Gated under the creator tab group so
24	// the shared TabBar stays visible; route matches the story AC
25	// (`app/(creator)/listing/[id].tsx`). Data flows through the
26	// get-listing-detail edge function (US-039) — that path is picked
27	// deliberately over direct PostgREST so it works around the current
28	// JWT-drift cascade that blocks gateway-verified table reads.
29	//
30	// Spec alignment (docs/design.md §4.2):
31	// - Back chevron header (lister handle deferred — requires a lister-profile
32	//   join the edge function does not yet expose; Spec gap noted in progress.txt).
33	// - Hero card with title, price, "Payout after approval" caption.
34	// - Sample videos rendered as tappable rows that open the URL in the
35	//   platform app via Linking.openURL — NOT embedded previews per the
36	//   design doc's "link-out only" v1 rule.
37	// - Eligibility rail: one row per PRE condition showing ✓/✗ plus the
38	//   required threshold and the creator's actual value (from the
39	//   edge-function `failed_conditions` additive `actual` field).
40	// - "What to film" post-condition bullet list (POST rows; not gated on
41	//   eligibility — reviewed at submission time, US-057+).
42	// - Sticky footer with the Apply CTA. Gate per §4.2:
43	//     eligible + !active-app  → ButtonPrimary "Apply to collab"
44	//     eligible + active-app   → StatusPill + disabled CTA
45	//     ineligible              → disabled CTA "Not eligible yet"
46	//     inactive listing        → no CTA, status banner at top
47	//
48	// Apply flow: tapping the CTA opens the ApplySheet (US-042) which posts
49	// to apply-to-listing (US-041). On success we toast + route to the
50	// Applied tab; on a server-state change (version bump, paused listing,
51	// already-applied, ineligible, not-found) we close the sheet and reload
52	// the detail so the eligibility rail / CTA reflect the new reality.
53	
54	type ListingRow = Database['public']['Tables']['listings']['Row'];
55	type ConditionRow = Database['public']['Tables']['listing_conditions']['Row'];
56	type SampleVideoRow = Database['public']['Tables']['sample_videos']['Row'];
57	type Platform = Database['public']['Enums']['platform'];
58	type ListingStatus = Database['public']['Enums']['listing_status'];
59	
60	type FailedCondition = {
61	  metric: string;
62	  platform: Platform | null;
63	  required: number | boolean;
64	  actual: number | boolean | null;
65	};
66	
67	type DetailResponse = {
68	  listing: ListingRow;
69	  conditions: ConditionRow[];
70	  sample_videos: SampleVideoRow[];
71	  eligibility: {
72	    eligible: boolean;
73	    failed_conditions: FailedCondition[];
74	    has_active_application: boolean;
75	  };
76	};
77	
78	type LoadState =
79	  | { kind: 'loading' }
80	  | { kind: 'error'; code: 'not_found' | 'generic' }
81	  | { kind: 'ok'; data: DetailResponse };
82	
83	export default function ListingDetail() {
84	  const { id } = useLocalSearchParams<{ id: string }>();
85	  const { show: showToast } = useToast();
86	  const [state, setState] = useState<LoadState>({ kind: 'loading' });
87	  const [applySheetOpen, setApplySheetOpen] = useState(false);
88	
89	  const load = useCallback(async () => {
90	    if (!id) {
91	      setState({ kind: 'error', code: 'not_found' });
92	      return;
93	    }
94	    setState({ kind: 'loading' });
95	    const { data, error } = await supabase.functions.invoke<DetailResponse>(
96	      'get-listing-detail',
97	      { body: { listing_id: id } },
98	    );
99	    if (error) {
100	      const ctx = (error as { context?: unknown }).context;
101	      if (
102	        ctx &&
103	        typeof ctx === 'object' &&
104	        'status' in ctx &&
105	        typeof (ctx as { json?: unknown }).json === 'function'
106	      ) {
107	        const res = ctx as Response;
108	        if (res.status === 404) {
109	          setState({ kind: 'error', code: 'not_found' });
110	          return;
111	        }
112	      }
113	      console.error('get-listing-detail failed', error);
114	      setState({ kind: 'error', code: 'generic' });
115	      return;
116	    }
117	    if (!data) {
118	      setState({ kind: 'error', code: 'generic' });
119	      return;
120	    }
121	    setState({ kind: 'ok', data });
122	  }, [id]);
123	
124	  useEffect(() => {
125	    void load();
126	  }, [load]);
127	
128	  const onBack = useCallback(() => {
129	    // Slot-based layouts don't maintain a full stack, so fall back to
130	    // the feed when back is unavailable (Codebase Pattern #27/#95).
131	    if (router.canGoBack()) {
132	      router.back();
133	    } else {
134	      router.replace('/(creator)/feed');
135	    }
136	  }, []);
137	
138	  const onApply = useCallback(() => {
139	    setApplySheetOpen(true);
140	  }, []);
141	
142	  const onApplied = useCallback(() => {
143	    setApplySheetOpen(false);
144	    showToast({
145	      message: 'Application sent.',
146	      variant: 'success',
147	    });
148	    // Per AC: route to the Applied tab. The actual route is
149	    // `/(creator)/applications` (US-031 layout); the AC's "(creator)/applied"
150	    // refers to the same logical tab. Defer the route swap until after the
151	    // BottomSheet's spring-out animation has settled (SPRING_SNAPPY ~300ms),
152	    // otherwise the sheet's slide-down plays on top of the new screen.
153	    setTimeout(() => router.replace('/(creator)/applications'), 350);
154	  }, [showToast]);
155	
156	  const onApplyFailure = useCallback(
157	    (failure: ApplyFailure) => {
158	      setApplySheetOpen(false);
159	      // Reload so the eligibility rail / CTA reflect the new server reality
160	      // (version bumped, listing paused, an existing application surfaced, etc.).
161	      if (
162	        failure.kind === 'version_changed' ||
163	        failure.kind === 'not_active' ||
164	        failure.kind === 'already_applied' ||
165	        failure.kind === 'ineligible' ||
166	        failure.kind === 'not_found'
167	      ) {
168	        void load();
169	      }
170	    },
171	    [load],
172	  );
173	
174	  const listingTitle = state.kind === 'ok' ? state.data.listing.title : '';
175	
176	  return (
177	    <SafeAreaView style={styles.container}>
178	      <Header onBack={onBack} />
179	      {state.kind === 'loading' ? (
180	        <View style={styles.centered}>
181	          <ActivityIndicator color={colors.ink} />
182	        </View>
183	      ) : state.kind === 'error' ? (
184	        <ErrorBody code={state.code} onBack={onBack} />
185	      ) : (
186	        <DetailBody data={state.data} onApply={onApply} />
187	      )}
188	      {id ? (
189	        <ApplySheet
190	          visible={applySheetOpen}
191	          listingId={id}
192	          listingTitle={listingTitle}
193	          onDismiss={() => setApplySheetOpen(false)}
194	          onApplied={onApplied}
195	          onServerStateChanged={onApplyFailure}
196	        />
197	      ) : null}
198	    </SafeAreaView>
199	  );
200	}
201	
202	function Header({ onBack }: { onBack: () => void }) {
203	  return (
204	    <View style={styles.header}>
205	      <Pressable
206	        onPress={onBack}
207	        hitSlop={spacing.md}
208	        accessibilityRole="button"
209	        accessibilityLabel="Back"
210	        testID="listing-back"
211	      >
212	        <ChevronLeft color={colors.ink} size={28} strokeWidth={2.5} />
213	      </Pressable>
214	      <Text style={[textStyles.h2, { color: colors.ink }]}>Campaign</Text>
215	      <View style={styles.headerSpacer} />
216	    </View>
217	  );
218	}
219	
220	function ErrorBody({
221	  code,
222	  onBack,
223	}: {
224	  code: 'not_found' | 'generic';
225	  onBack: () => void;
226	}) {
227	  const copy =
228	    code === 'not_found'
229	      ? 'This campaign is no longer available.'
230	      : 'Could not load this campaign. Try again in a moment.';
231	  return (
232	    <View style={styles.centered}>
233	      <Text style={[textStyles.h1, { color: colors.ink, textAlign: 'center' }]}>
234	        Campaign not found
235	      </Text>
236	      <Text
237	        style={[textStyles.body, { color: colors.ink70, textAlign: 'center', marginTop: spacing.sm }]}
238	      >
239	        {copy}
240	      </Text>
241	      <View style={{ marginTop: spacing.xl, minWidth: 160 }}>
242	        <ButtonPrimary label="Back to feed" onPress={onBack} testID="listing-error-back" />
243	      </View>
244	    </View>
245	  );
246	}
247	
248	function DetailBody({
249	  data,
250	  onApply,
251	}: {
252	  data: DetailResponse;
253	  onApply: () => void;
254	}) {
255	  const { listing, conditions, sample_videos, eligibility } = data;
256	
257	  const preConditions = useMemo(
258	    () => conditions.filter((c) => c.kind === 'pre'),
259	    [conditions],
260	  );
261	  const postConditions = useMemo(
262	    () => conditions.filter((c) => c.kind === 'post'),
263	    [conditions],
264	  );
265	
266	  const failureByKey = useMemo(() => {
267	    const map = new Map<string, FailedCondition>();
268	    for (const f of eligibility.failed_conditions) {
269	      map.set(conditionKey(f.metric, f.platform), f);
270	    }
271	    return map;
272	  }, [eligibility.failed_conditions]);
273	
274	  const inactiveBanner = getInactiveBanner(listing.status);
275	  const priceLabel = formatPrice(listing.price_cents, listing.currency);
276	
277	  return (
278	    <>
279	      <ScrollView
280	        contentContainerStyle={styles.scrollContent}
281	        showsVerticalScrollIndicator={false}
282	      >
283	        {inactiveBanner ? (
284	          <View style={styles.inactiveBanner} testID="listing-inactive-banner">
285	            <Text style={[textStyles.caption, { color: colors.ink }]}>
286	              {inactiveBanner}
287	            </Text>
288	          </View>
289	        ) : null}
290	
291	        <View style={styles.heroCard} testID="listing-hero">
292	          <Text style={[textStyles.display, { color: colors.ink }]}>
293	            {listing.title}
294	          </Text>
295	          <Text style={[textStyles.h1, styles.priceRow]} testID="listing-price">
296	            {priceLabel}
297	          </Text>
298	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
299	            Payout after approval
300	          </Text>
301	        </View>
302	
303	        {sample_videos.length > 0 ? (
304	          <Section title="Sample videos">
305	            <View style={styles.sampleList}>
306	              {sample_videos.map((v) => (
307	                <SampleVideoCell key={v.id} video={v} />
308	              ))}
309	            </View>
310	          </Section>
311	        ) : null}
312	
313	        {preConditions.length > 0 ? (
314	          <Section title="Eligibility">
315	            <View style={styles.eligibilityList}>
316	              {preConditions.map((c) => (
317	                <EligibilityRow
318	                  key={c.id}
319	                  condition={c}
320	                  failure={failureByKey.get(conditionKey(c.metric, c.platform)) ?? null}
321	                />
322	              ))}
323	            </View>
324	          </Section>
325	        ) : null}
326	
327	        {postConditions.length > 0 ? (
328	          <Section title="What to film">
329	            <View style={styles.bulletList}>
330	              {postConditions.map((c) => (
331	                <PostConditionRow key={c.id} condition={c} />
332	              ))}
333	            </View>
334	          </Section>
335	        ) : null}
336	
337	        {listing.description ? (
338	          <Section title="Brief">
339	            <Text style={[textStyles.body, { color: colors.ink }]}>
340	              {listing.description}
341	            </Text>
342	          </Section>
343	        ) : null}
344	      </ScrollView>
345	
346	      <FooterCta
347	        listing={listing}
348	        eligibility={eligibility}
349	        onApply={onApply}
350	      />
351	    </>
352	  );
353	}
354	
355	function FooterCta({
356	  listing,
357	  eligibility,
358	  onApply,
359	}: {
360	  listing: ListingRow;
361	  eligibility: DetailResponse['eligibility'];
362	  onApply: () => void;
363	}) {
364	  if (listing.status !== 'active') {
365	    // Inactive listing surfaces its state via the top banner; the CTA is
366	    // hidden outright — a disabled CTA would imply "apply later" which is
367	    // wrong for paused/closed.
368	    return null;
369	  }
370	  if (eligibility.has_active_application) {
371	    return (
372	      <View style={styles.footer}>
373	        <View style={styles.footerInner}>
374	          <StatusPill status="pending" label="Applied" testID="listing-applied-pill" />
375	          <View style={styles.footerCtaWrap}>
376	            <ButtonPrimary
377	              label="Applied"
378	              onPress={onApply}
379	              disabled
380	              testID="listing-cta"
381	            />
382	          </View>
383	        </View>
384	      </View>
385	    );
386	  }
387	  if (!eligibility.eligible) {
388	    return (
389	      <View style={styles.footer}>
390	        <View style={styles.failureSummary} testID="listing-failure-summary">
391	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>
392	            You don&apos;t meet these yet:
393	          </Text>
394	          {eligibility.failed_conditions.map((f) => (
395	            <View key={conditionKey(f.metric, f.platform)} style={styles.bulletRow}>
396	              <View style={styles.bullet} />
397	              <Text style={[textStyles.caption, styles.bulletText]}>
398	                {failureBulletLabel(f)}
399	              </Text>
400	            </View>
401	          ))}
402	        </View>
403	        <View style={styles.footerCtaWrap}>
404	          <ButtonPrimary
405	            label="Not eligible yet"
406	            onPress={onApply}
407	            disabled
408	            testID="listing-cta"
409	          />
410	        </View>
411	      </View>
412	    );
413	  }
414	  return (
415	    <View style={styles.footer}>
416	      <View style={styles.footerCtaWrap}>
417	        <ButtonPrimary
418	          label="Apply to collab"
419	          onPress={onApply}
420	          testID="listing-cta"
421	        />
422	      </View>
423	    </View>
424	  );
425	}
426	
427	function Section({ title, children }: { title: string; children: React.ReactNode }) {
428	  return (
429	    <View style={styles.section}>
430	      <Text style={[textStyles.h2, { color: colors.ink }]}>{title}</Text>
431	      {children}
432	    </View>
433	  );
434	}
435	
436	function SampleVideoCell({ video }: { video: SampleVideoRow }) {
437	  const label = platformLabel(video.platform);
438	  const onPress = useCallback(() => {
439	    void Linking.openURL(video.url).catch(() => {
440	      // Swallowed intentionally — the link may not resolve in the
441	      // simulator (no TikTok/Instagram app installed). There is no
442	      // actionable retry; the URL is the primary info for the creator.
443	    });
444	  }, [video.url]);
445	  return (
446	    <Pressable
447	      onPress={onPress}
448	      style={[styles.sampleRow, shadows.hard]}
449	      accessibilityRole="link"
450	      accessibilityLabel={`Open ${label} sample${video.caption ? `: ${video.caption}` : ''}`}
451	      testID={`listing-sample-${video.sort_order}`}
452	    >
453	      <View style={styles.sampleText}>
454	        <Text style={[textStyles.body, { color: colors.ink }]}>
455	          {video.caption ?? `${label} sample`}
456	        </Text>
457	        <Text style={[textStyles.caption, { color: colors.ink70 }]} numberOfLines={1}>
458	          {video.url}
459	        </Text>
460	      </View>
461	      <ExternalLink color={colors.ink} size={20} strokeWidth={2.5} />
462	    </Pressable>
463	  );
464	}
465	
466	function EligibilityRow({
467	  condition,
468	  failure,
469	}: {
470	  condition: ConditionRow;
471	  failure: FailedCondition | null;
472	}) {
473	  const passed = failure === null;
474	  const label = eligibilityRowLabel(condition);
475	  const statusColor = passed ? colors.success : colors.danger;
476	  const Icon = passed ? Check : X;
477	  const detail = passed
478	    ? requiredLabel(condition)
479	    : failureDetailLabel(condition, failure);
480	  return (
481	    <View
482	      style={styles.eligibilityRow}
483	      accessible
484	      accessibilityLabel={
485	        passed
486	          ? `${label} passes. Required ${requiredLabel(condition)}.`
487	          : `${label} fails. ${detail}.`
488	      }
489	      testID={`listing-eligibility-${condition.metric}-${condition.platform ?? 'none'}`}
490	    >
491	      <View style={[styles.eligibilityIcon, { borderColor: statusColor }]}>
492	        <Icon color={statusColor} size={16} strokeWidth={3} />
493	      </View>
494	      <View style={styles.eligibilityTextWrap}>
495	        <Text style={[textStyles.body, { color: colors.ink }]}>{label}</Text>
496	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>{detail}</Text>
497	      </View>
498	    </View>
499	  );
500	}
501	
