503	  return (
504	    <View style={styles.bulletRow}>
505	      <View style={styles.bullet} />
506	      <Text style={[textStyles.body, styles.bulletText]}>
507	        {postConditionLabel(condition)}
508	      </Text>
509	    </View>
510	  );
511	}
512	
513	function conditionKey(metric: string, platform: Platform | null): string {
514	  return `${metric}::${platform ?? '_'}`;
515	}
516	
517	function getInactiveBanner(status: ListingStatus): string | null {
518	  switch (status) {
519	    case 'paused':
520	      return 'This campaign is paused. The lister is reviewing pending applications.';
521	    case 'closed':
522	      return 'This campaign is closed and no longer accepting applications.';
523	    default:
524	      return null;
525	  }
526	}
