534	function metricLabel(metric: string): string {
535	  switch (metric) {
536	    case 'min_followers':
537	      return 'Minimum followers';
538	    case 'min_avg_views_last_n':
539	      return 'Avg views (last 10)';
540	    case 'min_total_likes':
541	      return 'Total likes';
542	    case 'min_videos_posted':
543	      return 'Videos posted';
544	    case 'verified_only':
545	      return 'Verified account';
546	    default:
547	      return metric;
548	  }
549	}
550	
551	function requiredLabel(c: ConditionRow): string {
552	  if (c.operator === 'bool') {
553	    return `Requires ${c.bool_threshold ? 'yes' : 'no'}`;
554	  }
555	  const threshold = c.numeric_threshold;
556	  if (threshold !== null && threshold !== undefined) {
557	    return `Requires ${formatCount(Number(threshold))}+`;
558	  }
559	  return '—';
560	}
