563	  c: ConditionRow,
564	  f: FailedCondition,
565	): string {
566	  const required = requiredLabel(c);
567	  if (typeof f.actual === 'number') {
568	    return `${required} — you have ${formatCount(f.actual)}`;
569	  }
570	  if (typeof f.actual === 'boolean') {
571	    return `${required} — you are ${f.actual ? 'verified' : 'not verified'}`;
572	  }
573	  return `${required} — no data yet`;
574	}
