576	function failureBulletLabel(f: FailedCondition): string {
577	  const platform = f.platform ? platformLabel(f.platform) : '';
578	  const base = metricLabel(f.metric);
579	  const label = platform ? `${platform} · ${base}` : base;
580	  if (typeof f.required === 'boolean') {
581	    return `${label} — need ${f.required ? 'yes' : 'no'}`;
582	  }
583	  const needed = formatCount(f.required);
584	  if (typeof f.actual === 'number') {
