628	  const code = currency.toUpperCase();
629	  if (code === 'USD') return `$${amount}`;
630	  return `${amount} ${code}`;
631	}
632	
633	function formatCount(n: number): string {
634	  if (n < 1000) return String(n);
635	  const trim = (value: number, digits: number): string => {
636	    const fixed = value.toFixed(digits);
637	    return fixed.endsWith('.0') ? fixed.slice(0, -2) : fixed;
638	  };
639	  if (n < 1_000_000) return `${trim(n / 1000, n < 10_000 ? 1 : 0)}k`;
640	  if (n < 1_000_000_000) return `${trim(n / 1_000_000, n < 10_000_000 ? 1 : 0)}m`;
641	  return `${trim(n / 1_000_000_000, n < 10_000_000_000 ? 1 : 0)}b`;
642	}
