1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import {
3	  Pressable,
4	  SafeAreaView,
5	  ScrollView,
6	  StyleSheet,
7	  Text,
8	  View,
9	  type StyleProp,
10	  type ViewStyle,
11	} from 'react-native';
12	import { router } from 'expo-router';
13	import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
14	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
15	import { useToast } from '@/components/primitives/Toast';
16	import { colors, radii, shadows, spacing } from '@/design/tokens';
17	import { textStyles } from '@/design/typography';
18	import { useAuth } from '@/lib/auth';
19	import { getCachedToken } from '@/lib/storage';
20	import { supabase } from '@/lib/supabase';
21	import { formatRelativeTime } from '@/lib/time';
22	import type { Database } from '@/types/supabase';
23	
24	// US-043 — Creator "My Applications" tab. Calls the `list_my_applications`
25	// SECURITY DEFINER RPC which joins applications → listings → users (lister
26	// handle) → listing_versions (snapshot title) under the caller's auth.uid
27	// and returns a flat shape the UI can render directly. The RPC exists
28	// because a plain PostgREST embed would silently null the lister handle
29	// (users RLS is self-only) and the version title for non-active listings
30	// (listing_versions RLS is gated on listing.status='active').
31	//
32	// Segments: Pending / Approved / Rejected / Cancelled per AC.
33	// DB enum has 6 values; withdrawn + cancelled_listing_* all bucket to
34	// "Cancelled" per design §3.1 label + AC's 4-segment design. Route path
35	// matches docs/design.md:151 canonical URL `/(creator)/applications`.
36	//
37	// US-044 extends this screen with a Supabase Realtime subscription on
38	// UPDATEs to `public.applications` filtered by `creator_id=me`. On status
39	// change we patch the affected row in state (so it visibly jumps to the
40	// new segment without a reload) and fire a success/error toast for the
41	// two decisions the AC calls out: approved and rejected. The applications
42	// table was added to the `supabase_realtime` publication in the companion
43	// migration `us_044_applications_realtime_publication`. RLS
44	// (`applications_creator_rw`, polcmd='*') already restricts the stream to
45	// the caller's own rows — the client-side filter is an additional
46	// throughput guard, not the security boundary.
47	
48	type ApplicationStatus = Database['public']['Enums']['application_status'];
49	type Segment = 'pending' | 'approved' | 'rejected' | 'cancelled';
50	type ApplicationRow = Database['public']['Functions']['list_my_applications']['Returns'][number];
51	
52	const STATUS_BUCKET: Record<ApplicationStatus, Segment> = {
53	  pending: 'pending',
54	  approved: 'approved',
55	  rejected: 'rejected',
56	  withdrawn: 'cancelled',
57	  cancelled_listing_edit: 'cancelled',
58	  cancelled_listing_closed: 'cancelled',
59	};
60	
61	const SEGMENTS: readonly { key: Segment; label: string }[] = [
62	  { key: 'pending', label: 'Pending' },
63	  { key: 'approved', label: 'Approved' },
64	  { key: 'rejected', label: 'Rejected' },
65	  { key: 'cancelled', label: 'Cancelled' },
66	];
67	
68	// Segmented control semantics: a11y role "tab" with single-select state.
69	// Chip primitive (checkbox role) is for multi-select filter rows — a
70	// segmented control needs single-select. Keeping this inline rather than
71	// promoting to a shared primitive until another screen needs it.
72	type SegmentControlProps = {
73	  active: Segment;
74	  onChange: (next: Segment) => void;
75	};
76	
77	function SegmentControl({ active, onChange }: SegmentControlProps) {
78	  return (
79	    <View style={styles.segmentRow} accessibilityRole="tablist">
80	      {SEGMENTS.map((s) => (
81	        <SegmentButton
82	          key={s.key}
83	          label={s.label}
84	          selected={active === s.key}
85	          onPress={() => onChange(s.key)}
86	          testID={`segment-${s.key}`}
87	        />
88	      ))}
89	    </View>
90	  );
91	}
92	
93	type SegmentButtonProps = {
94	  label: string;
95	  selected: boolean;
96	  onPress: () => void;
97	  testID?: string;
98	};
99	
100	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
101	  const bg = selected ? colors.primarySoft : colors.surface;
102	  const textColor = selected ? colors.primaryDeep : colors.ink;
103	  return (
104	    <Pressable
105	      onPress={onPress}
106	      accessibilityRole="tab"
107	      accessibilityState={{ selected }}
108	      accessibilityLabel={label}
109	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
110	      testID={testID}
111	    >
112	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
113	        {label}
114	      </Text>
115	    </Pressable>
116	  );
117	}
118	
119	export default function Applications() {
120	  const { user } = useAuth();
121	  const userId = user?.id ?? null;
122	  const { show: showToast } = useToast();
123	
124	  const [segment, setSegment] = useState<Segment>('pending');
125	  const [rows, setRows] = useState<ApplicationRow[]>([]);
126	  const [loading, setLoading] = useState(true);
127	  const [error, setError] = useState<string | null>(null);
128	
129	  // Realtime handler reads the prior status to detect real transitions
130	  // (no-op UPDATEs shouldn't trigger a toast). A ref mirrors `rows` so the
131	  // subscription callback sees the latest state without re-subscribing on
132	  // every list mutation.
133	  const rowsRef = useRef<ApplicationRow[]>([]);
134	  useEffect(() => {
135	    rowsRef.current = rows;
136	  }, [rows]);
137	
138	  const load = useCallback(async () => {
139	    if (!userId) return;
140	    setLoading(true);
141	    setError(null);
142	    const { data, error: rpcError } = await supabase.rpc('list_my_applications');
143	    if (rpcError) {
144	      setError("Couldn't load applications.");
145	      setRows([]);
146	    } else {
147	      setRows(data ?? []);
148	    }
149	    setLoading(false);
150	  }, [userId]);
151	
152	  useEffect(() => {
153	    void load();
154	  }, [load]);
155	
156	  // US-044 — Subscribe to UPDATE events on the caller's own applications.
157	  // RLS (`applications_creator_rw`) enforces the security boundary; the
158	  // `creator_id=eq.<id>` filter is a client-side throughput guard so the
159	  // Realtime broker doesn't ship rows we'll discard. We use
160	  // `supabase.realtime.setAuth(token)` for the same reason as the US-036
161	  // pattern (Codebase Pattern #105) — websocket auth doesn't go through
162	  // the marketifyFetch Authorization wrapper.
163	  useEffect(() => {
164	    if (!userId) return;
165	    const token = getCachedToken();
166	    if (!token) return;
167	    let cancelled = false;
168	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
169	    void supabase.realtime.setAuth(token).then(() => {
170	      if (cancelled) return;
171	      activeChannel = supabase
172	        .channel(`creator-applications-${userId}`)
173	        .on(
174	          'postgres_changes',
175	          {
176	            event: 'UPDATE',
177	            schema: 'public',
178	            table: 'applications',
179	            filter: `creator_id=eq.${userId}`,
180	          },
181	          (payload) => {
182	            const next = payload.new as { id?: string; status?: ApplicationStatus };
183	            if (!next.id || !next.status) return;
184	            const prior = rowsRef.current.find((r) => r.id === next.id);
185	            if (!prior) return;
186	            if (prior.status === next.status) return;
187	            const nextStatus = next.status;
188	            setRows((cur) =>
189	              cur.map((r) => (r.id === next.id ? { ...r, status: nextStatus } : r)),
190	            );
191	            if (nextStatus === 'approved') {
192	              showToast({
193	                message: 'Your application was approved',
194	                variant: 'success',
195	              });
196	            } else if (nextStatus === 'rejected') {
197	              showToast({
198	                message: 'Your application was rejected',
199	                variant: 'error',
200	              });
201	            }
202	          },
203	        )
204	        .subscribe();
205	    });
206	    return () => {
207	      cancelled = true;
208	      if (activeChannel) void supabase.removeChannel(activeChannel);
209	    };
210	  }, [userId, showToast]);
211	
212	  const byBucket = useMemo(() => {
213	    const map: Record<Segment, ApplicationRow[]> = {
214	      pending: [],
215	      approved: [],
216	      rejected: [],
217	      cancelled: [],
218	    };
219	    for (const r of rows) {
220	      map[STATUS_BUCKET[r.status]].push(r);
221	    }
222	    return map;
223	  }, [rows]);
224	
225	  const visible = byBucket[segment];
226	
227	  return (
228	    <SafeAreaView style={styles.root}>
229	      <ScrollView contentContainerStyle={styles.scroll}>
230	        <Text style={[textStyles.display, styles.header]}>Applied</Text>
231	        <SegmentControl active={segment} onChange={setSegment} />
232	
233	        {loading ? (
234	          <View style={styles.list} testID="applications-loading">
235	            <SkeletonCard />
236	            <SkeletonCard />
237	          </View>
238	        ) : error ? (
239	          <View style={styles.emptyBox}>
240	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
241	          </View>
242	        ) : visible.length === 0 ? (
243	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
244	            <Text style={[textStyles.body, { color: colors.ink70 }]}>
245	              {emptyMessageFor(segment)}
246	            </Text>
247	          </View>
248	        ) : (
249	          <View style={styles.list}>
250	            {visible.map((row) => (
251	              <ApplicationRowCard key={row.id} row={row} />
252	            ))}
253	          </View>
254	        )}
255	      </ScrollView>
256	    </SafeAreaView>
257	  );
258	}
259	
260	function emptyMessageFor(segment: Segment): string {
261	  switch (segment) {
262	    case 'pending':
263	      return 'No pending applications yet. Apply from Discover.';
264	    case 'approved':
265	      return 'Nothing approved yet — keep applying.';
266	    case 'rejected':
267	      return 'No rejections here.';
268	    case 'cancelled':
269	      return 'No cancelled applications.';
270	  }
271	}
272	
273	type ApplicationRowCardProps = {
274	  row: ApplicationRow;
275	  style?: StyleProp<ViewStyle>;
