591	  switch (c.metric) {
592	    case 'post_family_friendly':
593	      return c.bool_threshold ? 'Family-friendly content only.' : 'Content may be mature.';
594	    case 'post_must_mention':
595	      return c.text_threshold
596	        ? `Must mention ${c.text_threshold}.`
597	        : 'Must include a specific mention.';
598	    case 'post_must_tag_account':
599	      return c.text_threshold
600	        ? `Must tag @${c.text_threshold.replace(/^@/, '')}.`
601	        : 'Must tag the lister account.';
602	    case 'post_min_video_duration_sec':
603	      return c.numeric_threshold !== null
604	        ? `Video at least ${c.numeric_threshold}s.`
605	        : 'Minimum video duration.';
606	    case 'post_max_video_duration_sec':
607	      return c.numeric_threshold !== null
608	        ? `Video at most ${c.numeric_threshold}s.`
609	        : 'Maximum video duration.';
610	    case 'post_min_video_count':
611	      return c.numeric_threshold !== null
612	        ? `Post at least ${c.numeric_threshold} videos.`
613	        : 'Minimum video count.';
614	    default:
615	      return c.metric;
616	  }
617	}
