1	import {
2	  createContext,
3	  useCallback,
4	  useContext,
5	  useEffect,
6	  useMemo,
7	  useRef,
8	  useState,
9	} from 'react';
10	import {
11	  type LayoutChangeEvent,
12	  Pressable,
13	  SafeAreaView,
14	  StyleSheet,
15	  Text,
16	  View,
17	} from 'react-native';
18	import Animated, {
19	  cancelAnimation,
20	  Easing,
21	  useAnimatedStyle,
22	  useSharedValue,
23	  withSpring,
24	  withTiming,
25	  type WithSpringConfig,
26	} from 'react-native-reanimated';
27	import { X } from 'lucide-react-native';
28	import { colors, radii, shadows, spacing } from '@/design/tokens';
29	import { SPRING_SNAPPY, withReducedMotion } from '@/design/motion';
30	import { useReducedMotion } from '@/design/useReducedMotion';
31	import { textStyles } from '@/design/typography';
32	
33	// Global toast banner per docs/design.md §6 inventory (`message, variant, duration`)
34	// and §1.4 line 439 ("2.5s success toast"). Mount ToastProvider once near the root
35	// (app/_layout.tsx) and call useToast().show({...}) from anywhere.
36	//
37	// Variants drive the soft-bg + border color from the semantic palette in §1.2.
38	// Progress bar counts down the remaining duration so the user can gauge when it
39	// will auto-dismiss.
40	
41	export type ToastVariant = 'success' | 'error' | 'info';
42	
43	export type ToastPayload = {
44	  message: string;
45	  variant?: ToastVariant;
46	  duration?: number; // ms, default 2500
47	};
48	
49	type ToastContextValue = {
50	  show: (t: ToastPayload) => void;
51	  hide: () => void;
52	};
53	
54	const DEFAULT_DURATION = 2500;
55	
56	const ToastContext = createContext<ToastContextValue | null>(null);
57	
58	export function useToast(): ToastContextValue {
59	  const ctx = useContext(ToastContext);
60	  if (!ctx) {
61	    throw new Error('useToast must be used inside <ToastProvider>');
62	  }
63	  return ctx;
64	}
65	
66	type InternalToast = {
67	  id: number;
68	  message: string;
69	  variant: ToastVariant;
70	  duration: number;
71	};
72	
73	export function ToastProvider({ children }: { children: React.ReactNode }) {
74	  const [toast, setToast] = useState<InternalToast | null>(null);
75	  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
76	
77	  const clearTimer = useCallback(() => {
78	    if (timerRef.current) {
79	      clearTimeout(timerRef.current);
80	      timerRef.current = null;
81	    }
82	  }, []);
83	
84	  const hide = useCallback(() => {
85	    clearTimer();
86	    setToast(null);
87	  }, [clearTimer]);
88	
89	  const show = useCallback(
90	    (t: ToastPayload) => {
91	      clearTimer();
92	      const id = Date.now();
93	      const duration = t.duration ?? DEFAULT_DURATION;
94	      setToast({
95	        id,
96	        message: t.message,
97	        variant: t.variant ?? 'info',
98	        duration,
99	      });
100	      timerRef.current = setTimeout(() => {
101	        timerRef.current = null;
102	        // Only clear if this toast still owns the slot (show() may have replaced it).
103	        setToast((cur) => (cur?.id === id ? null : cur));
104	      }, duration);
105	    },
106	    [clearTimer],
107	  );
108	
109	  useEffect(() => () => clearTimer(), [clearTimer]);
110	
111	  const value = useMemo<ToastContextValue>(() => ({ show, hide }), [show, hide]);
112	
113	  return (
114	    <ToastContext.Provider value={value}>
115	      {children}
116	      {toast ? <ToastSurface toast={toast} onDismiss={hide} /> : null}
117	    </ToastContext.Provider>
118	  );
119	}
120	
121	type VariantPalette = { bg: string; border: string };
122	
123	const VARIANT_PALETTE: Record<ToastVariant, VariantPalette> = {
124	  success: { bg: colors.successSoft, border: colors.success },
125	  error: { bg: colors.dangerSoft, border: colors.danger },
126	  info: { bg: colors.primarySoft, border: colors.primary },
127	};
128	
129	type ToastSurfaceProps = {
130	  toast: InternalToast;
131	  onDismiss: () => void;
132	};
133	
134	function ToastSurface({ toast, onDismiss }: ToastSurfaceProps) {
135	  const reduced = useReducedMotion();
136	  const translateY = useSharedValue(-140);
137	  const progress = useSharedValue(1);
138	  const trackWidth = useSharedValue(0);
139	
140	  useEffect(() => {
141	    // Reset each time a new toast replaces the slot (toast.id changes) so the
142	    // enter spring + progress countdown replay from their start positions.
143	    translateY.value = -140;
144	    translateY.value = withSpring(
145	      0,
146	      withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
147	    );
148	    progress.value = 1;
149	    if (!reduced) {
150	      progress.value = withTiming(0, {
151	        duration: toast.duration,
152	        easing: Easing.linear,
153	      });
154	    }
155	    return () => {
156	      cancelAnimation(translateY);
157	      cancelAnimation(progress);
158	    };
159	  }, [toast.id, toast.duration, reduced, translateY, progress]);
160	
161	  const handleTrackLayout = (event: LayoutChangeEvent) => {
162	    trackWidth.value = event.nativeEvent.layout.width;
163	  };
164	
165	  const bannerStyle = useAnimatedStyle(() => ({
166	    transform: [{ translateY: translateY.value }],
167	  }));
168	
169	  const progressFillStyle = useAnimatedStyle(() => ({
170	    width: trackWidth.value * progress.value,
171	  }));
172	
173	  const palette = VARIANT_PALETTE[toast.variant];
174	
175	  return (
176	    <SafeAreaView pointerEvents="box-none" style={styles.root}>
177	      <Animated.View
178	        pointerEvents="auto"
179	        style={[
180	          styles.banner,
181	          { backgroundColor: palette.bg, borderColor: palette.border },
182	          shadows.hard,
183	          bannerStyle,
184	        ]}
185	        accessibilityRole="alert"
186	      >
187	        <View style={styles.row}>
188	          <Text
189	            style={[textStyles.body, styles.message, { color: colors.ink }]}
190	            numberOfLines={3}
191	            allowFontScaling={false}
192	          >
193	            {toast.message}
194	          </Text>
195	          <Pressable
196	            onPress={onDismiss}
197	            accessibilityRole="button"
198	            accessibilityLabel="Dismiss notification"
199	            hitSlop={8}
200	          >
201	            <X size={18} color={colors.ink} strokeWidth={2.5} />
202	          </Pressable>
203	        </View>
204	        <View
205	          style={[styles.progressTrack, { backgroundColor: colors.surface }]}
206	          onLayout={handleTrackLayout}
207	        >
208	          <Animated.View
209	            style={[styles.progressFill, { backgroundColor: palette.border }, progressFillStyle]}
210	          />
211	        </View>
212	      </Animated.View>
213	    </SafeAreaView>
214	  );
215	}
216	
217	const styles = StyleSheet.create({
218	  root: {
219	    position: 'absolute',
220	    top: 0,
221	    left: 0,
222	    right: 0,
223	    alignItems: 'center',
224	    zIndex: 9999,
225	    elevation: 9999,
226	  },
227	  banner: {
228	    marginTop: spacing.sm,
229	    width: '92%',
230	    maxWidth: 520,
231	    borderRadius: radii.card,
232	    borderWidth: 2,
233	    paddingVertical: spacing.md,
234	    paddingHorizontal: spacing.base,
235	  },
236	  row: {
237	    flexDirection: 'row',
238	    alignItems: 'center',
239	    gap: spacing.sm,
240	  },
241	  message: {
242	    flex: 1,
243	  },
244	  progressTrack: {
245	    marginTop: spacing.sm,
246	    height: 3,
247	    borderRadius: radii.pill,
248	    overflow: 'hidden',
249	  },
250	  progressFill: {
251	    height: '100%',
252	    borderRadius: radii.pill,
253	  },
